-- Clean CTE duplicate records ranking target filter
WITH dedupped AS (
  SELECT id, email,
         ROW_NUMBER() OVER (PARTITION BY email ORDER BY created_at DESC) as rn
  FROM users
) SELECT id, email FROM dedupped WHERE rn = 1;

-- Native JSON path query selector
SELECT JSON_VALUE(json_payload, '$.user.email') as email
FROM raw_api_logs;

-- Short-circuiting EXISTS validation checks
SELECT name FROM users u WHERE EXISTS (
  SELECT 1 FROM logs l WHERE l.user_id = u.id
);

-- Array elements row expansion
SELECT item_id, tag
FROM items CROSS JOIN UNNEST(tags_list) as tag;

-- Native epoch seconds calculation
SELECT EXTRACT(EPOCH FROM (timestamp2 - timestamp1)) as diff_seconds
FROM logs;

-- Force database planner to materialize CTE cache view
WITH heavy_step AS MATERIALIZED (
  SELECT user_id, count(*) as cnt FROM logs GROUP BY user_id
) SELECT * FROM heavy_step WHERE cnt > 100;

-- Query execution plan query inspector
EXPLAIN ANALYZE
SELECT user_id, sum(score) FROM user_scores GROUP BY user_id;

