-- Native First Value index fetcher
SELECT FIRST_VALUE(event) OVER (PARTITION BY user_id ORDER BY time) as first_action
FROM session_logs;

-- Equal size cohort splitter
SELECT user_id, NTILE(10) OVER (ORDER BY score DESC) as decile
FROM user_metrics;

-- Dynamic evaluation rows cross joins
SELECT u.id, t.name
FROM users u, LATERAL UNNEST(u.tags) as t(name);

-- Recursive CTE hierarchy loop
WITH RECURSIVE tree AS (
  SELECT id, parent_id, 1 as lvl FROM nodes WHERE parent_id IS NULL
  UNION ALL
  SELECT n.id, n.parent_id, t.lvl + 1 FROM nodes n JOIN tree t ON n.parent_id = t.id
) SELECT * FROM tree;

-- Difference sequential rows grouping
WITH grouped AS (
  SELECT user_id, dt,
         dt - ROW_NUMBER() OVER (PARTITION BY user_id ORDER BY dt) as group_id
  FROM logins
) SELECT user_id, min(dt), max(dt), count(*) FROM grouped GROUP BY user_id, group_id;

-- Latest record profile tracking filter
WITH ranked AS (
  SELECT id, ROW_NUMBER() OVER (PARTITION BY email ORDER BY created DESC) as rn
  FROM users
) SELECT id FROM ranked WHERE rn = 1;

-- Complete sequential dates calendar generator
WITH RECURSIVE calendar AS (
  SELECT DATE('2025-01-01') as dt
  UNION ALL
  SELECT dt + 1 FROM calendar WHERE dt < '2025-01-10'
) SELECT * FROM calendar;
